      );
  }
});

// Handle SPA routing: serve index.html for any unknown routes
app.get('*', (req, res) => {
  if (fs.existsSync(indexPath)) {
    res.sendFile(indexPath);
  } else {
    logger.error(`Deployment Error: index.html not found at ${indexPath}`);
    res
      .status(404)
      .send(
        "Frontend build files not found. Please ensure 'npm run build' completed successfully."
      );
  }
});

// Handle Graceful Shutdown for Render
process.on('SIGTERM', () => {
  logger.info('SIGTERM signal received: closing HTTP server');
  server.close(() => {
    mainBot.stop('SIGTERM'); // Stop main bot
    adminBot.stop('SIGTERM'); // Stop admin bot
    mongoose.connection
      .close()
      .then(() => logger.info('Database connection closed.'));
  });
});

// Render requires binding to 0.0.0.0 to be reachable externally
const HOST = '0.0.0.0';

server.listen(PORT, HOST, () => {
  logger.info('>>> Server process successfully bound to port', {
    port: PORT,
    host: HOST,
    nodeEnv: process.env.NODE_ENV,
  });

  if (process.env.NODE_ENV === 'production') {
    if (!process.env.TELEGRAM_BOT_TOKEN)
      logger.warn('TELEGRAM_BOT_TOKEN is not set!');
    if (!process.env.FRONTEND_URL)
      logger.warn('FRONTEND_URL is not set! CORS might block connections.');
    logger.info(`Production Mode: Static files serving from /dist`, {
      corsOrigin: process.env.FRONTEND_URL,
    });
  }
});

import React, { Component, ErrorInfo, ReactNode } from 'react';

interface Props {
  children?: ReactNode;
  fallback?: ReactNode;
}
interface State {
  hasError: boolean;
}

class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false
  };

  public static getDerivedStateFromError(_: Error): State {
    return { hasError: true };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    const msg = String(error?.message ?? '').replace(/[\r\n]/g, ' ');
    const stack = String(errorInfo?.componentStack ?? '').replace(/[\r\n]/g, ' ');
    console.error("Uncaught error:", msg, stack);
  }

  public render() {
    if (this.state.hasError) {
      // You can render any custom fallback UI
      if (this.props.fallback) {
        return this.props.fallback;
      }
      return (
        <div className="flex-1 flex flex-col items-center justify-center p-8 text-center bg-[#0f170a]">
          <h1 className="text-red-500 text-2xl font-black uppercase italic tracking-tighter mb-4">
            Something went wrong
          </h1>
          <p className="text-gray-400 text-sm mb-8 max-w-xs leading-relaxed font-medium">An unexpected error occurred. Please try reloading the application.</p>
          <button onClick={() => window.location.reload()} className="px-8 py-3 bg-white text-black rounded-xl font-black uppercase text-xs tracking-widest shadow-xl active:scale-95 transition-transform">
            Reload Page
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

